import type { FilterFieldLogicalOperatorNode } from '../../../types/conversion-utils.js';
import type {
  FilterFieldLeafNode,
  FilterFieldListNode,
  FilterFieldNode,
} from '../../../types/tree-nodes.js';
import { isFilterFieldValueNode } from '../../tree-node-guards.js';

/**
 * Mutates the given node to override the type with 'Error'.
 * @internal
 */
export function convertToErrorNode(
  node?: Partial<
    FilterFieldLeafNode | FilterFieldListNode | FilterFieldLogicalOperatorNode
  >,
) {
  if (node === undefined) {
    return;
  }

  node.type = 'Error';

  if (!Array.isArray(node.value)) {
    node.value = node.textValue;
  }
}

/**
 * Mutates the given node, appending the given text to 'value' and 'textValue'.
 * If the 'value' argument is provided, it will be used instead of the 'text' to update the node's 'value'.
 * @internal
 */
export function updateNodeValues(
  node: Partial<FilterFieldNode>,
  text: string,
  value?: string,
) {
  if (!isFilterFieldValueNode(node)) {
    return;
  }

  node.textValue = `${node.textValue ?? ''}${text}`;
  node.value = `${node.value ?? ''}${value ?? text}`;
}
